import React from 'react';
import styled from 'styled-components';
import { useTheme } from '../context/ThemeContext';
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome';
import { faLightbulb, faUsers, faRocket } from '@fortawesome/free-solid-svg-icons';

const MissionSection = styled.section`
  padding: 100px 20px;
  position: relative;
  overflow: hidden;
  background: ${props => props.isDarkTheme 
    ? 'linear-gradient(120deg, rgba(0, 27, 47, 0.9), rgba(56, 0, 61, 0.9))'
    : 'linear-gradient(120deg, rgba(255, 255, 255, 0.9), rgba(240, 240, 255, 0.9))'};
  transition: background 0.3s ease;

  &::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background: url(${require('../assets/backgrounf.png')}) no-repeat center center / cover;
    opacity: ${props => props.isDarkTheme ? 0.1 : 0.05};
    z-index: 0;
    transition: opacity 0.3s ease;
  }
`;

const Container = styled.div`
  max-width: 1200px;
  margin: 0 auto;
  position: relative;
  z-index: 1;
`;

const Title = styled.h2`
  text-align: center;
  font-size: 3rem;
  margin-bottom: 50px;
  color: transparent;
  -webkit-text-stroke: 1px ${props => props.isDarkTheme ? '#00FFFF' : '#008B8B'};
  position: relative;
  transition: all 0.3s ease;

  &::after {
    content: '';
    position: absolute;
    bottom: -10px;
    left: 50%;
    transform: translateX(-50%);
    width: 150px;
    height: 3px;
    background: ${props => props.isDarkTheme 
      ? 'linear-gradient(to right, #00FFFF, #00BFFF)' 
      : 'linear-gradient(to right, #008B8B, #006666)'};
    transition: background 0.3s ease;
  }
`;

const CardGrid = styled.div`
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));
  gap: 30px;
  padding: 20px;
`;

const Card = styled.div`
  background: ${props => props.isDarkTheme 
    ? 'rgba(255, 255, 255, 0.05)' 
    : 'rgba(0, 0, 0, 0.05)'};
  backdrop-filter: blur(10px);
  border: 1px solid ${props => props.isDarkTheme 
    ? 'rgba(255, 255, 255, 0.1)' 
    : 'rgba(0, 0, 0, 0.1)'};
  border-radius: 15px;
  padding: 40px 30px;
  text-align: center;
  transition: all 0.4s ease;
  position: relative;
  overflow: hidden;
  
  &::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background: ${props => props.isDarkTheme
      ? 'linear-gradient(45deg, transparent, rgba(0, 255, 255, 0.1), transparent)'
      : 'linear-gradient(45deg, transparent, rgba(0, 139, 139, 0.1), transparent)'};
    transform: translateX(-100%);
    transition: transform 0.6s ease;
  }

  &:hover {
    transform: translateY(-10px);
    box-shadow: ${props => props.isDarkTheme
      ? '0 20px 40px rgba(0, 255, 255, 0.1)'
      : '0 20px 40px rgba(0, 139, 139, 0.1)'};
    border-color: ${props => props.isDarkTheme
      ? 'rgba(0, 255, 255, 0.3)'
      : 'rgba(0, 139, 139, 0.3)'};
  }

  &:hover::before {
    transform: translateX(100%);
  }

  .icon {
    font-size: 3rem;
    color: ${props => props.isDarkTheme ? '#00FFFF' : '#008B8B'};
    margin-bottom: 20px;
    transition: all 0.3s ease;
    filter: drop-shadow(0 0 10px ${props => props.isDarkTheme 
      ? 'rgba(0, 255, 255, 0.3)' 
      : 'rgba(0, 139, 139, 0.3)'});
  }

  &:hover .icon {
    transform: scale(1.1);
    filter: drop-shadow(0 0 15px ${props => props.isDarkTheme 
      ? 'rgba(0, 255, 255, 0.5)' 
      : 'rgba(0, 139, 139, 0.5)'});
  }

  h3 {
    color: ${props => props.isDarkTheme ? '#00FFFF' : '#008B8B'};
    font-size: 1.8rem;
    margin-bottom: 15px;
    transition: color 0.3s ease;
  }

  p {
    color: ${props => props.isDarkTheme 
      ? 'rgba(255, 255, 255, 0.8)' 
      : 'rgba(0, 0, 0, 0.8)'};
    line-height: 1.6;
    font-size: 1.1rem;
    transition: color 0.3s ease;
  }
`;

const Mission = () => {
  const { theme, isDarkTheme } = useTheme();

  const missions = [
    {
      icon: faLightbulb,
      title: "Innovation",
      description: "Fostering creative thinking and innovative solutions in technology"
    },
    {
      icon: faUsers,
      title: "Collaboration",
      description: "Building a community of passionate tech enthusiasts"
    },
    {
      icon: faRocket,
      title: "Growth",
      description: "Empowering students to reach their full potential in tech"
    }
  ];

  return (
    <MissionSection isDarkTheme={isDarkTheme}>
      <Container>
        <Title isDarkTheme={isDarkTheme} data-aos="fade-up">
          Our Mission
        </Title>
        <CardGrid>
          {missions.map((mission, index) => (
            <Card 
              key={index}
              isDarkTheme={isDarkTheme}
              data-aos="fade-up"
              data-aos-delay={index * 100}
            >
              <FontAwesomeIcon icon={mission.icon} className="icon" />
              <h3>{mission.title}</h3>
              <p>{mission.description}</p>
            </Card>
          ))}
        </CardGrid>
      </Container>
    </MissionSection>
  );
};

export default Mission;
